#!/usr/bin/env python3
import subprocess as s, os
have = s.run(['swapon','--show'], capture_output=True, text=True).stdout.strip()
if have:
    print('swap already present:', ' | '.join(have.splitlines()))
else:
    if s.run(['fallocate','-l','8G','/swapfile']).returncode != 0:
        s.run(['dd','if=/dev/zero','of=/swapfile','bs=1M','count=8192'])
    os.chmod('/swapfile', 0o600)
    s.run(['mkswap','/swapfile'])
    s.run(['swapon','/swapfile'])
    try:
        fst = open('/etc/fstab').read()
    except Exception:
        fst = ''
    if '/swapfile' not in fst:
        open('/etc/fstab','a').write('/swapfile none swap sw 0 0\n')
    print('swap created + enabled')
s.run(['sysctl','-w','vm.swappiness=10'])
open('/etc/sysctl.d/99-atlas-lifeline.conf','w').write('vm.swappiness=10\n')
print(s.run(['free','-h'], capture_output=True, text=True).stdout)
print('LIFELINE seq-124: swap + swappiness=10 in place; PG cannot be OOM-killed by memory pressure.')
